def validate_signature(payload: bytes, signature: str, secret: str) -> bool:
    """Validate HMAC-SHA256 signature from the partner."""
    if not secret:
        logger.warning("WEBHOOK_SECRET is not configured")
        return False

    if not signature:
        logger.warning("No signature provided in request")
        return False

    # Support "sha256=<hex>" format (common in webhook implementations)
    if signature.startswith("sha256="):
        signature = signature[7:]

    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected_signature, signature)


