def validate_timestamp(timestamp: str, max_age_seconds: int = 300) -> tuple[bool, str]:
    """Validate that the webhook timestamp is not too old (replay protection)."""
    try:
        event_time = datetime.fromisoformat(timestamp.replace("Z", "+00:00"))
        now = datetime.now(timezone.utc)
        age = abs((now - event_time).total_seconds())

        if age > max_age_seconds:
            return False, f"Webhook timestamp is too old ({age:.0f}s > {max_age_seconds}s)"

        return True, ""
    except (ValueError, TypeError) as e:
        return False, f"Invalid timestamp format: {e}"


